// Global route middleware — the `.global` suffix auto-registers
// this for every navigation. `@sidebase/nuxt-auth` exposes
// `useAuth()` as an auto-import that returns the current session.

export default defineNuxtRouteMiddleware((to) => {
  const publicRoutes = new Set<string>(["/", "/about", "/auth/sign-in", "/auth/sign-up"])
  if (publicRoutes.has(to.path)) return

  const { status } = useAuth()
  if (status.value !== "authenticated") {
    return navigateTo("/auth/sign-in")
  }
})
